import { describe, it, expect } from 'vitest';
import { signPayload, sanitizePayload } from '../lib/crypto.js';

describe('Crypto Utilities', () => {
  describe('signPayload', () => {
    it('produces sha256= prefixed HMAC hex digest', () => {
      const sig = signPayload('{"test":1}', 'secret123');
      expect(sig).toMatch(/^sha256=[a-f0-9]{64}$/);
    });

    it('produces deterministic signatures', () => {
      const a = signPayload('body', 'key');
      const b = signPayload('body', 'key');
      expect(a).toBe(b);
    });

    it('differs with different secrets', () => {
      const a = signPayload('body', 'key1');
      const b = signPayload('body', 'key2');
      expect(a).not.toBe(b);
    });
  });

  describe('sanitizePayload', () => {
    it('returns undefined for undefined input', () => {
      expect(sanitizePayload(undefined)).toBeUndefined();
    });

    it('passes through safe keys untouched', () => {
      const input = { command: 'ls -la', file_path: '/tmp/foo.ts' };
      expect(sanitizePayload(input)).toEqual(input);
    });

    // --- Sensitive key redaction ---

    it('redacts keys containing "password"', () => {
      const result = sanitizePayload({ user_password: 'hunter2' });
      expect(result?.user_password).toBe('[REDACTED]');
    });

    it('redacts keys containing "secret"', () => {
      const result = sanitizePayload({ client_secret: 'abc123' });
      expect(result?.client_secret).toBe('[REDACTED]');
    });

    it('redacts keys containing "token"', () => {
      const result = sanitizePayload({ access_token: 'xyz' });
      expect(result?.access_token).toBe('[REDACTED]');
    });

    it('redacts keys containing "key" (case-insensitive)', () => {
      const result = sanitizePayload({ apiKey: 'sk-test' });
      expect(result?.apiKey).toBe('[REDACTED]');
    });

    it('redacts keys containing "credential"', () => {
      const result = sanitizePayload({ db_credential: 'root:pass' });
      expect(result?.db_credential).toBe('[REDACTED]');
    });

    it('redacts keys containing "auth"', () => {
      const result = sanitizePayload({ authHeader: 'Bearer xyz' });
      expect(result?.authHeader).toBe('[REDACTED]');
    });

    // --- Embedded secret detection in values ---

    it('redacts OpenAI API keys in Bash commands', () => {
      const result = sanitizePayload({
        command: 'export OPENAI_API_KEY=sk-abcdefghijklmnopqrstuvwxyz1234567890',
      });
      expect(result?.command).not.toContain('sk-abcdefghijklmnopqrstuvwxyz1234567890');
      expect(result?.command).toContain('[REDACTED]');
    });

    it('redacts GitHub PATs in commands', () => {
      const result = sanitizePayload({
        command: 'git clone https://ghp_1234567890abcdefghijklmnopqrstuvwxyz1234@github.com/user/repo',
      });
      expect(result?.command).not.toContain('ghp_1234567890abcdefghijklmnopqrstuvwxyz1234');
    });

    it('redacts Bearer tokens', () => {
      const result = sanitizePayload({
        command: 'curl -H "Authorization: Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.abc"',
      });
      expect(result?.command).toContain('[REDACTED]');
      expect(result?.command).not.toContain('eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.abc');
    });

    it('redacts env var assignments with secret names', () => {
      const result = sanitizePayload({
        command: 'export API_KEY=supersecretvalue123456',
      });
      expect(result?.command).toContain('[REDACTED]');
    });

    // --- String truncation ---

    it('truncates strings longer than 500 chars', () => {
      const longString = 'x'.repeat(600);
      const result = sanitizePayload({ content: longString });
      expect((result?.content as string).length).toBeLessThanOrEqual(500);
      expect((result?.content as string).endsWith('...')).toBe(true);
    });

    it('does not truncate strings at exactly 500 chars', () => {
      const exact = 'x'.repeat(500);
      const result = sanitizePayload({ content: exact });
      expect(result?.content).toBe(exact);
    });

    // --- Recursive sanitization ---

    it('recursively sanitizes nested objects', () => {
      const result = sanitizePayload({
        outer: { inner_password: 'secret', safe_field: 'visible' },
      });
      const outer = result?.outer as Record<string, unknown>;
      expect(outer.inner_password).toBe('[REDACTED]');
      expect(outer.safe_field).toBe('visible');
    });

    it('sanitizes objects inside arrays', () => {
      const result = sanitizePayload({
        items: [{ api_token: 'leaked' }, { name: 'safe' }],
      });
      const items = result?.items as Array<Record<string, unknown>>;
      expect(items[0].api_token).toBe('[REDACTED]');
      expect(items[1].name).toBe('safe');
    });

    // --- Real-world webhook payload simulation ---

    it('sanitizes a realistic Bash tool_input payload', () => {
      const result = sanitizePayload({
        command: 'curl -H "Authorization: Bearer sk-ant-api03-LONGAPIKEY12345678901234567890" https://api.anthropic.com/v1/messages',
        description: 'Call Anthropic API',
        timeout: 30000,
      });
      expect(result?.command).toContain('[REDACTED]');
      expect(result?.description).toBe('Call Anthropic API');
      expect(result?.timeout).toBe(30000);
    });
  });
});
